-- ---------------------------------------------------------- Tabel structuur voor tabel tips_tabel -- ---------------------------------------------------------- DROP TABLE IF EXISTS tips_tabel;CREATE TABLE tips_tabel (tip_id int(11) NOT NULL auto_increment,persoon_id int(11) NOT NULL default '0',tip_niveau int(10) default NULL,-- allemaal vooronderzoek, afkick, star, start, duurzaamheid, heroverweging-- maar vooralsnog geoon het strategieniveautip_gewicht int(11) default '0',---zelf toegekend gewichttip_reactie int(11) default '0',tip_categorie varchar(35) default NULL,tip_tekst varchar(100) default NULL,PRIMARY KEY (tip_id),KEY persoon_id (persoon_id),KEY tip_niveau (tip_niveau)) TYPE=MyISAM AUTO_INCREMENT=1000 ;-- INSERT INTO tips_tabel ( tip_id , persoon_id , tip_niveau , tip_gewicht , tip_reactie , tip_categorie , tip_tekst ) -- VALUES (-- '', '5', '4', '0', '0', 'test', 'testtsettsetsetsetsetsetsetse'-- ); -- Gegevens worden uitgevoerd voor tabel tips_tabel-- 